const now = new Date();
const months = ['January','February','March','April','May','June','July','August','September','October','November','December'];
const currentMonth = months[now.getMonth()];
const nextMonth = months[(now.getMonth() + 1) % 12];

const fmtHuman = d => d.toLocaleDateString('en-GB', {
  weekday: 'short', day: 'numeric', month: 'long'
});

const weekends = [];
const base = new Date(now);
const dow = base.getDay();
let daysToFri = (5 - dow + 7) % 7;
if (daysToFri === 0) daysToFri = 7;
base.setDate(base.getDate() + daysToFri);

for (let i = 0; i < 3; i++) {
  const fri = new Date(base);
  const sun = new Date(base);
  sun.setDate(sun.getDate() + 2);
  weekends.push({ label: `${fmtHuman(fri)} – ${fmtHuman(sun)}`, index: i + 1 });
  base.setDate(base.getDate() + 7);
}

const mondayDate = now.toLocaleDateString('en-GB', {
  weekday: 'long', day: 'numeric', month: 'long', year: 'numeric'
});

const queries = [
  {
    id: 1, label: 'Motorsport & 4x4',
    q: `Kenya car rally OR motorsport OR 4x4 OR overlanding event Nanyuki OR Laikipia OR Nyeri ${currentMonth} OR ${nextMonth} 2026`
  },
  {
    id: 2, label: 'Running & Outdoor Events',
    q: `marathon OR fun run OR cycling OR hiking event Nanyuki OR Nyeri OR "Mt Kenya" OR Laikipia 2026 ${currentMonth} OR ${nextMonth}`
  },
  {
    id: 3, label: 'Conservancy Events',
    q: `"Ol Pejeta" OR "Solio Ranch" OR Lewa OR Laikipia event OR "open day" OR festival OR marathon 2026 ${currentMonth} OR ${nextMonth}`
  },
  {
    id: 4, label: 'Public Holidays & School Terms',
    q: 'Kenya public holidays school holiday term dates 2026 April May June'
  },
  {
    id: 5, label: 'Major Annual Events',
    q: '"Nanyuki Airshow 2026" OR "Lewa Safari Marathon 2026" OR "Mt Kenya Marathon 2026" OR "Rhino Charge Kenya 2026" OR "East African Safari Classic 2026"'
  },
  {
    id: 6, label: 'General Nanyuki Demand',
    q: `Nanyuki events ${currentMonth} 2026 Laikipia festival OR event ${nextMonth} 2026`
  },
  {
    id: 7, label: 'Facebook Group Signals',
    q: `site:facebook.com Nanyuki hiking OR climbing OR "road trip" ${currentMonth} 2026`
  }
];

return queries.map(q => ({ json: { ...q, currentMonth, nextMonth, mondayDate, weekends } }));

const queryMeta = $('Search Loop').item.json;
const resp = $input.item.json;

const results = Array.isArray(resp.results) ? resp.results : [];
const success = results.length > 0;

const snippets = results.slice(0, 5).map(r =>
  `• ${r.title || '(no title)'}\n  ${r.content || ''}\n  ${r.url || ''}`
).join('\n\n');

return [{
  json: {
    queryId: queryMeta.id,
    label: queryMeta.label,
    success,
    resultCount: results.length,
    snippets: snippets || '(no results found)',
    currentMonth: queryMeta.currentMonth,
    nextMonth: queryMeta.nextMonth,
    mondayDate: queryMeta.mondayDate,
    weekends: queryMeta.weekends
  }
}];

const resp = $input.item.json;
const buildNode = $('Build Claude Prompt').item.json;

const content = resp.content?.[0]?.text || '';

if (!content || content.length < 100) {
  throw new Error('Claude returned empty or very short response \u2014 check API key and quota');
}

const sheetsMatch = content.match(/---SHEETS_DATA---\s*([\s\S]*?)\s*---END_SHEETS---/);
let sheetsData = { events: 'NONE', w1: 'UNKNOWN', w2: 'UNKNOWN', w3: 'UNKNOWN', groups: '' };

if (sheetsMatch) {
  try { sheetsData = JSON.parse(sheetsMatch[1].trim()); } catch (e) {}
}

const emailBody = content.replace(/---SHEETS_DATA---[\s\S]*?---END_SHEETS---/, '').trim();
const fullBody = buildNode.failureNote + emailBody;

function esc(t) { return String(t).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;'); }
function bold(t) { return esc(t).replace(/\*\*(.*?)\*\*/g,'<strong>$1</strong>'); }

function badgeHtml(signal) {
  const s = (signal || 'UNKNOWN').trim();
  const map = {
    HIGH:'background:#d4edda;color:#155724',
    MEDIUM:'background:#fff3cd;color:#856404',
    LOW:'background:#cce5ff;color:#004085',
    UNKNOWN:'background:#e2e3e5;color:#495057'
  };
  const style = map[s] || map.UNKNOWN;
  return '<span style="display:inline-block;padding:2px 10px;font-size:11px;font-weight:700;' + style + ';border-radius:2px;letter-spacing:.5px">' + s + '</span>';
}

function buildCalendar(text) {
  const blocks = text.split(/(?=WEEKEND \d+:)/).filter(b => /WEEKEND \d+:/.test(b));
  let out = '<div style="background:#fff;border:1px solid #d4cfc4;padding:20px 22px;margin-bottom:14px">'
    + '<div style="font-size:10px;letter-spacing:2.5px;text-transform:uppercase;color:#6b7160;margin-bottom:14px">Demand Calendar</div>';
  for (const block of blocks) {
    const lines = block.split('\n').map(l => l.trim()).filter(Boolean);
    const titleLine = lines[0];
    const wNum = (titleLine.match(/WEEKEND (\d+)/) || [])[1] || '';
    const dateRange = titleLine.replace(/WEEKEND \d+:\s*/, '');
    let event = '', signal = '', context = '';
    for (const line of lines.slice(1)) {
      if (line.startsWith('Event or signal:')) event = line.slice('Event or signal:'.length).trim();
      else if (line.startsWith('Demand signal:')) signal = line.slice('Demand signal:'.length).trim();
      else if (line.startsWith('One line of context:')) context = line.slice('One line of context:'.length).trim();
    }
    out += '<div style="border:1px solid #e8e3d8;padding:14px 16px;margin-bottom:10px">'
      + '<div style="font-size:14px;font-weight:700;color:#4a5240;margin-bottom:10px">Weekend ' + wNum + ' \u00b7 ' + esc(dateRange) + '</div>'
      + '<div style="margin-bottom:7px"><div style="font-size:10px;letter-spacing:1px;text-transform:uppercase;color:#6b7160;margin-bottom:1px">Event or Signal</div>'
      + '<div style="font-size:14px;line-height:1.5">' + bold(event) + '</div></div>'
      + '<div style="margin-bottom:7px"><div style="font-size:10px;letter-spacing:1px;text-transform:uppercase;color:#6b7160;margin-bottom:3px">Demand Signal</div>'
      + badgeHtml(signal) + '</div>'
      + '<div><div style="font-size:10px;letter-spacing:1px;text-transform:uppercase;color:#6b7160;margin-bottom:1px">Context</div>'
      + '<div style="font-size:14px;line-height:1.5">' + bold(context) + '</div></div>'
      + '</div>';
  }
  return out + '</div>';
}

function buildGroups(lines) {
  const groups = [];
  let cur = null;
  for (const line of lines) {
    if (line.startsWith('- ')) {
      if (cur) groups.push(cur);
      cur = { name: line.slice(2), lookFor: '', action: '' };
    } else if (cur && line.startsWith('What to look for:')) cur.lookFor = line.slice('What to look for:'.length).trim();
    else if (cur && line.startsWith('Action:')) cur.action = line.slice('Action:'.length).trim();
  }
  if (cur) groups.push(cur);
  let out = '<div style="background:#fff;border:1px solid #d4cfc4;padding:20px 22px;margin-bottom:14px">'
    + '<div style="font-size:10px;letter-spacing:2.5px;text-transform:uppercase;color:#6b7160;margin-bottom:14px">Facebook Groups to Check</div>';
  if (!groups.length) {
    out += '<p style="font-size:14px;line-height:1.65;margin:0">' + bold(lines.join(' ')) + '</p>';
  } else {
    for (const g of groups) {
      out += '<div style="padding:11px 0;border-bottom:1px solid #e8e3d8">'
        + '<div style="font-size:14px;font-weight:700;color:#4a5240;margin-bottom:4px">' + esc(g.name) + '</div>'
        + (g.lookFor ? '<div style="font-size:13px;color:#555;margin-bottom:2px"><strong>Look for:</strong> ' + esc(g.lookFor) + '</div>' : '')
        + (g.action ? '<div style="font-size:13px;color:#555"><strong>Action:</strong> ' + esc(g.action) + '</div>' : '')
        + '</div>';
    }
  }
  return out + '</div>';
}

function buildAction(lines) {
  const text = lines.join('\n');
  const postMatch = text.match(/\*"([\s\S]*?)"\*/);
  let intro = text, postCopy = '';
  if (postMatch) { intro = text.slice(0, postMatch.index).trim(); postCopy = postMatch[1].trim(); }
  return '<div style="background:#4a5240;padding:20px 22px;margin-bottom:14px">'
    + '<div style="font-size:10px;letter-spacing:2.5px;text-transform:uppercase;color:rgba(255,255,255,.55);margin-bottom:10px">One Action for Today</div>'
    + '<div style="font-size:14px;color:#fff;line-height:1.65">' + bold(intro).replace(/\n/g, '<br>')
    + (postCopy
      ? '<div style="background:rgba(255,255,255,.12);border-left:3px solid #b5913a;padding:12px 14px;margin-top:12px;font-size:13px;font-style:italic;color:rgba(255,255,255,.9);line-height:1.6">\u201c' + esc(postCopy) + '\u201d</div>'
      : '')
    + '</div></div>';
}

function buildFlags(lines) {
  let out = '<div style="background:#fff;border:1px solid #d4cfc4;padding:20px 22px;margin-bottom:14px">'
    + '<div style="font-size:10px;letter-spacing:2.5px;text-transform:uppercase;color:#6b7160;margin-bottom:14px">School & Public Holiday Flags</div>';
  for (const line of lines) {
    if (line) out += '<div style="font-size:14px;line-height:1.6;padding:6px 0;border-bottom:1px solid #e8e3d8">' + bold(line) + '</div>';
  }
  return out + '</div>';
}

function buildSummary(lines) {
  return '<div style="background:#fff;border:1px solid #d4cfc4;border-left:3px solid #4a5240;padding:20px 22px;margin-bottom:14px">'
    + '<div style="font-size:10px;letter-spacing:2.5px;text-transform:uppercase;color:#6b7160;margin-bottom:10px">Summary</div>'
    + '<p style="font-size:14px;line-height:1.7;margin:0">' + bold(lines.join(' ')) + '</p></div>';
}

function buildGeneric(lines) {
  let out = '<div style="background:#fff;border:1px solid #d4cfc4;padding:20px 22px;margin-bottom:14px">';
  for (const line of lines) {
    out += '<p style="font-size:14px;line-height:1.65;margin:0 0 8px">' + bold(line) + '</p>';
  }
  return out + '</div>';
}

function toHtml(text, mondayDate) {
  const sections = text.split(/\n---\n/).map(s => s.trim()).filter(Boolean);
  let body = '';
  for (const sec of sections) {
    const lines = sec.split('\n').map(l => l.trim()).filter(Boolean);
    if (!lines.length) continue;
    const h = lines[0].replace(/\*\*/g, '').trim();
    if (h === 'DEMAND CALENDAR') body += buildCalendar(sec);
    else if (h === 'FACEBOOK GROUPS TO CHECK THIS WEEK') body += buildGroups(lines.slice(1));
    else if (h === 'ONE ACTION FOR TODAY') body += buildAction(lines.slice(1));
    else if (h === 'SCHOOL HOLIDAY AND PUBLIC HOLIDAY FLAGS') body += buildFlags(lines.slice(1));
    else if (h.startsWith('SUMMARY')) body += buildSummary(lines.slice(1));
    else body += buildGeneric(lines);
  }
  return '<!DOCTYPE html><html><head><meta charset="UTF-8"><meta name="viewport" content="width=device-width,initial-scale=1"></head>'
    + '<body style="margin:0;padding:0;background:#f5f0e8;font-family:\'Helvetica Neue\',Arial,sans-serif;color:#2c2c2c">'
    + '<div style="max-width:620px;margin:0 auto;padding:20px">'
    + '<div style="background:#4a5240;padding:28px 24px;margin-bottom:14px">'
    + '<div style="color:#fff;font-size:21px;font-weight:600;margin-bottom:4px">Demand Intelligence</div>'
    + '<div style="color:rgba(255,255,255,.65);font-size:11px;letter-spacing:2px;text-transform:uppercase">Week of ' + esc(mondayDate) + ' \u00b7 Idan Barn Suites &amp; Caf\u00e9</div>'
    + '</div>' + body
    + '<div style="text-align:center;font-size:11px;color:#9a9590;padding:10px">Generated every Monday 07:00 EAT \u00b7 Naromoru, Kenya</div>'
    + '</div></body></html>';
}

const emailHtml = toHtml(fullBody, buildNode.mondayDate);

return [{
  json: {
    emailBody: fullBody,
    emailHtml,
    subject: `Nanyuki \u2014 Week of ${buildNode.mondayDate}`,
    sheetsData,
    mondayDate: buildNode.mondayDate
  }
}];
